import json
data = json.load(open('functions.json'))
print('functions.json ufunc entries:', len(data))
cxx = px = h = 0
for name, sig in data.items():
    for header in sig:
        if header.endswith('++'):
            cxx += 1
        elif header.endswith('.pxd'):
            px += 1
        else:
            h += 1
print('header-field refs -> C++ (++) =', cxx, ' .pxd =', px, ' .h =', h)
